CREATE PROCEDURE fetch_user_data ()
{
  DECLARE meta, _dt any;
  DECLARE inx INTEGER;
  EXEC ('SELECT U_ID, U_NAME FROM users WHERE U_DOB IS NOT NULL', null, null, null, 0, meta, _dt);
  inx := 0;
  EXEC_RESULT_NAMES(meta[0]);
  WHILE (inx < LENGTH(_dt))
    {
      EXEC_RESULT(_dt[inx]);
      inx := inx + 1;
    }
};

CREATE PROCEDURE aggregate_user_transactions ()
{
  DECLARE meta, _dt any;
  DECLARE inx INTEGER;
  EXEC ('SELECT U_ID, SUM(T_AMOUNT) FROM transactions GROUP BY U_ID HAVING SUM(T_AMOUNT) > 0', null, null, null, 0, meta, _dt);
  inx := 0;
  EXEC_RESULT_NAMES(meta[0]);
  WHILE (inx < LENGTH(_dt))
    {
      EXEC_RESULT(_dt[inx]);
      inx := inx + 1;
    }
};
